local function DropItem(self, item, wholestack, randomdir, pos, skipfall, tossdir, setspeed, ...) local owner = self.inst local itemInHand = item and self:GetEquippedItem(EQUIPSLOTS.HANDS) if owner and item and itemInHand and item == itemInHand and owner:GetCharacterEnchantmentBonus( "noslippyhand" ) > 0x0 and not owner.dycIsManualEquipOrUnequip and not item.dycIsRemoving then if item and item.parent then item.Transform:SetPosition(0x0, 0x0, 0x0) if item.Physics then item.Physics:SetVel(0x0, 0x0, 0x0) end end return end return self.dycOldDropItem(self, item, wholestack, randomdir, pos, skipfall, tossdir, setspeed, ...) end local function Equip(self, item, old_to_active, ...) return self.dycOldEquip(self, item, old_to_active, ...) end local function Unequip(self, equipslot, ...) local owner = self.inst local item = equipslot and self:GetEquippedItem(equipslot) local isRemoving = item and item.dycIsRemoving if owner and equipslot and equipslot == EQUIPSLOTS.HANDS and owner:GetCharacterEnchantmentBonus( "noslippyhand" ) > 0x0 and not owner.dycIsManualEquipOrUnequip and not isRemoving then return end return self.dycOldUnequip(self, equipslot, ...) end local function DYCInv(self) self.dycOldDropItem = self.DropItem self.DropItem = DropItem self.dycOldEquip = self.Equip self.Equip = Equip self.dycOldUnequip = self.Unequip self.Unequip = Unequip end return DYCInv 